var topic = msg.topic;
var payload = msg.payload;

// Convert payload to 1 or 0
var state = (payload === 'true' || payload === true || payload === 'ON' || payload === 'on') ? 1 : 0;

// Check that topic starts with "fgfs/"
if (!topic.startsWith('fgfs/')) return null;

// Remove "fgfs/" from topic for FlightGear
var fgPath = topic.slice(5); // tar bort de första 5 tecknen "fgfs/"

// Set payload for FlightGear
msg.payload = fgPath + ',' + state + '\n';

return msg;

let msgs = [];

if (!msg.payload.plane || !msg.payload.plane.switch) return null;

msg.payload.plane.switch.forEach(sw => {
    let name = sw.$.name.trim();
    let path = sw._.trim();

    let id = name.toLowerCase().replace(/ /g, "-");

    // Create Home Assistant discovery
    msgs.push({
        topic: `homeassistant/switch/fgfs_${id}/config`,
        payload: JSON.stringify({
            name: `FGFS ${name}`,
            unique_id: `fgfs_${id}`,
            command_topic: `fgfs/${path}`,   // direkt path
            state_topic: `fgfs/${path}`,
            payload_on: "true",
            payload_off: "false",
            state_on: "true",
            state_off: "false"
        }),
        retain: true
    });

    // Send initial value to FG 1/0
    let fgValue = 0;
    if (msg.payload[id] === true || msg.payload[id] === "true") {
        fgValue = 1;
    }

    msgs.push({
        topic: `fgfs/${path}`,
        payload: fgValue.toString(),
        retain: true
    });
});

return [msgs];
